import json
import sys
import subprocess
import os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}
    resp = ev.get("tool_response") or {}

    if tool != "Edit":
        return 0

    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    if not os.path.exists(file_path):
        return 0

    # Try flake8 first (catches undefined names), fall back to py_compile
    try:
        result = subprocess.run(
            ["flake8", "--select=F821,E999", file_path],
            capture_output=True,
            text=True,
            timeout=5
        )
        if result.returncode != 0 and result.stdout.strip():
            print(f"REQUIRED FOLLOW-UP: Python static analysis found errors in {file_path}:\n{result.stdout}\nFix each error before proceeding.", file=sys.stderr)
            return 2
    except (FileNotFoundError, subprocess.TimeoutExpired):
        # flake8 not available or timed out, fall back to compile check
        try:
            with open(file_path, 'r') as f:
                compile(f.read(), file_path, 'exec')
        except SyntaxError as e:
            print(f"REQUIRED FOLLOW-UP: Python syntax error in {file_path} at line {e.lineno}: {e.msg}\nFix each error before proceeding.", file=sys.stderr)
            return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())
